import React, { useState, useEffect } from 'react';
import axios from 'axios';

function App() {
  const [students, setStudents] = useState([]);

  // 1. Ka soo qaad liiska ardayda Backend-kaaga
  useEffect(() => {
    axios.get('http://localhost:3000/students')
      .then(res => setStudents(res.data))
      .catch(err => console.log("Backend-ku ma shaqaynayo ama ma jiro arday la diiwaangeliyey"));
  }, []);

  // 2. Shaqada Sax (Jooga) iyo Qalad (Maqan)
  const markAttendance = async (id, status) => {
    try {
      await axios.post(`http://localhost:3000/attendance/${id}`, { xaadir: status });
      alert(status ? "Ardayga waa la SAXAY (√)" : "Ardayga waa la QALDAY (X)");
    } catch (err) {
      alert("Cillad: Hubi in Backend-ku uu shaqaynayo!");
    }
  };

  return (
    <div style={{ padding: '40px', fontFamily: 'Segoe UI', textAlign: 'center' }}>
      <h1 style={{ color: '#2c3e50' }}>Nidaamka Xaadiriska Dugsiga</h1>
      <table border="1" style={{ width: '100%', borderCollapse: 'collapse', marginTop: '20px', boxShadow: '0 0 10px rgba(0,0,0,0.1)' }}>
        <thead>
          <tr style={{ backgroundColor: '#34495e', color: 'white' }}>
            <th style={{ padding: '15px' }}>Magaca Ardayga</th>
            <th>Fasalka</th>
            <th>Meesha Dhalashada</th>
            <th>Xaadiris (Maanta)</th>
          </tr>
        </thead>
        <tbody>
          {students.length > 0 ? students.map(std => (
            <tr key={std._id}>
              <td style={{ padding: '12px' }}>{std.magaca}</td>
              <td>{std.fasalka}</td>
              <td>{std.meesha_dhalashada}</td>
              <td>
                <button 
                  onClick={() => markAttendance(std._id, true)} 
                  style={{ backgroundColor: '#27ae60', color: 'white', border: 'none', padding: '8px 20px', cursor: 'pointer', borderRadius: '4px', marginRight: '10px' }}>
                  √ Sax
                </button>
                <button 
                  onClick={() => markAttendance(std._id, false)} 
                  style={{ backgroundColor: '#e74c3c', color: 'white', border: 'none', padding: '8px 20px', cursor: 'pointer', borderRadius: '4px' }}>
                  X Qalad
                </button>
              </td>
            </tr>
          )) : (
            <tr>
              <td colSpan="4" style={{ padding: '20px' }}>Ma jiraan arday weli la diiwaangeliyey.</td>
            </tr>
          )}
        </tbody>
      </table>
    </div>
  );
}

export default App;
